agent-browser eval "
const releases = document.querySelectorAll('.release-timeline .release');
const results = [];
releases.forEach(r => {
  const version = r.querySelector('.release__version')?.textContent?.trim();
  const date = r.querySelector('time')?.getAttribute('datetime') || r.querySelector('time')?.textContent?.trim();
  const isPre = r.querySelector('.badge--warning') !== null || r.querySelector('.badge--danger') !== null;
  results.push({ version, date, isPre });
});
JSON.stringify(results);
"

